// App.js
import React, { useState, useEffect } from 'react';
import Login from './Login';
import Dashboard from './Dashboard';

const App = () => {
  const [accessToken, setAccessToken] = useState(null);
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const token = localStorage.getItem('access_token');
    const tokenExpiry = localStorage.getItem('token_expiry');
    
    if (token && tokenExpiry && Date.now() < parseInt(tokenExpiry)) {
      setAccessToken(token);
      fetchUserInfo(token);
    } else {
      localStorage.removeItem('access_token');
      localStorage.removeItem('token_expiry');
      setLoading(false);
    }
  }, []);

  const fetchUserInfo = async (token) => {
    try {
      const response = await fetch('https://your-oauth-provider.com/userinfo', {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });
      const userData = await response.json();
      setUser(userData);
    } catch (error) {
      console.error('Error fetching user info:', error);
      handleLogout();
    } finally {
      setLoading(false);
    }
  };

  const handleLoginSuccess = (token, expiresIn) => {
    const expiryTime = Date.now() + (expiresIn * 1000);
    localStorage.setItem('access_token', token);
    localStorage.setItem('token_expiry', expiryTime.toString());
    setAccessToken(token);
    fetchUserInfo(token);
  };

  const handleLogout = () => {
    localStorage.removeItem('access_token');
    localStorage.removeItem('token_expiry');
    setAccessToken(null);
    setUser(null);
  };

  if (loading) {
    return <div style={{ textAlign: 'center', marginTop: '50px' }}>Loading...</div>;
  }

  return (
    <div>
      {!accessToken ? (
        <Login onLoginSuccess={handleLoginSuccess} />
      ) : (
        <Dashboard user={user} onLogout={handleLogout} accessToken={accessToken} />
      )}
    </div>
  );
};

export default App;


// Login.js
import React, { useEffect } from 'react';
import { parseTokenFromUrl } from './authUtils';

const Login = ({ onLoginSuccess }) => {
  useEffect(() => {
    const params = parseTokenFromUrl();
    
    if (params.access_token) {
      const expiresIn = params.expires_in ? parseInt(params.expires_in) : 3600;
      onLoginSuccess(params.access_token, expiresIn);
      window.history.replaceState({}, document.title, window.location.pathname);
    }
  }, [onLoginSuccess]);

  const handleLogin = () => {
    const authConfig = {
      authorizationEndpoint: 'https://your-oauth-provider.com/oauth/authorize',
      clientId: 'YOUR_CLIENT_ID',
      redirectUri: window.location.origin,
      scope: 'openid profile email',
      responseType: 'token'
    };

    const authUrl = buildAuthUrl(authConfig);
    window.location.href = authUrl;
  };

  const buildAuthUrl = (config) => {
    const params = new URLSearchParams({
      client_id: config.clientId,
      redirect_uri: config.redirectUri,
      response_type: config.responseType,
      scope: config.scope,
      state: generateRandomState()
    });

    return `${config.authorizationEndpoint}?${params.toString()}`;
  };

  const generateRandomState = () => {
    const array = new Uint8Array(16);
    window.crypto.getRandomValues(array);
    return Array.from(array, byte => byte.toString(16).padStart(2, '0')).join('');
  };

  return (
    <div style={{ textAlign: 'center', marginTop: '100px' }}>
      <h1>Welcome to OAuth SPA</h1>
      <button 
        onClick={handleLogin}
        style={{
          padding: '12px 24px',
          fontSize: '16px',
          backgroundColor: '#007bff',
          color: 'white',
          border: 'none',
          borderRadius: '4px',
          cursor: 'pointer'
        }}
      >
        Login with OAuth
      </button>
    </div>
  );
};

export default Login;


